<template>
  <v-card class="mt-10">

      <v-tabs bg-color="indigo" v-model="tab">
        <v-tab
          v-for="(day, index) in dayNames"
          :key="index"
          :value="day"
          stacked
        >  
          {{ day }}
        </v-tab>
      </v-tabs>
      
      <v-card-text>

      <v-tabs-window v-model="tab">
        <v-tabs-window-item v-for="(day, index) in days" :key="index" :value="dayNames[index]">
            <v-container>
            <v-row>
                <v-col cols="3" class="text-center">
                
                    <v-icon class="text-h2" :icon="day.icon.name" :color="day.icon.color"></v-icon>
                    
                </v-col>

                <v-col cols="9">
                    <div class="text-h6">{{ day.forecast }}</div>
                    <div>Ortalama sıcaklık: <b>{{ day.averageTemperature }}</b> °C</div>
                    <div>En yüksek sıcaklık: <b>{{ day.highestTemperature }}</b> °C</div>
                    <div>En düşük sıcaklık: <b>{{ day.lowestTemperature }}</b> °C</div>
                    <div>Koords: {{ lat }}, {{ lon }}</div>
                </v-col>
            </v-row>
            </v-container>
        </v-tabs-window-item>
      </v-tabs-window>
      </v-card-text>
  </v-card>
</template>

<script setup>
import { ref, defineProps, toRefs, watch } from 'vue';

import getWeatherData from '../services/getWeatherData.js';
import { decodeWeatherCode, getIconForWeatherCode } from '@/services/decodeWeatherCode.js';
import get7Days from '../services/get7Days.js'

// Tabs
const tab = ref(0);

const days = ref([]);
const dayNames = ref(get7Days())

// Coordinates
const props = defineProps({
    coords: Object,
})
const { coords } = toRefs(props);
const lat = ref(coords.value.lat);
const lon = ref(coords.value.lon);

// Get and display data
function getAndDisplayData() {
  getWeatherData(lat.value, lon.value).then(data => {
      days.value = []
      console.log("weather data:", data)
      let hourly = data.hourly
      let oldDay = 0

      let todaysWeatherCodes = []
      let todaysTemperatures = []
      for (let i = 0; i < hourly.time.length; i++) {
          

          // code to be run on every hour
          todaysWeatherCodes.push(hourly.weather_code[i])
          todaysTemperatures.push(hourly.temperature_2m[i])

          // 2024-05-30T00:00
          let day = parseInt(hourly.time[i].split("T")[0].split("-")[2])
          if (day != oldDay) {
              oldDay = day;

              // code to be run on every day
              

              let mostImportantCode = Math.max(...todaysWeatherCodes)

              const average = array => array.reduce((a, b) => a + b) / array.length;
              days.value.push({
                  day: day,
                  forecast: decodeWeatherCode(mostImportantCode),
                  icon: getIconForWeatherCode(mostImportantCode),
                  averageTemperature: parseInt(average(todaysTemperatures)),
                  highestTemperature: Math.max(...todaysTemperatures),
                  lowestTemperature:  Math.min(...todaysTemperatures),
              })

              todaysWeatherCodes = [];
              todaysTemperatures = []
          }
      }
  })
}
getAndDisplayData()
watch(coords, () => {

  lat.value = coords.value.lat;
  lon.value = coords.value.lon;
  getAndDisplayData()
})

</script>